import { resolve } from 'node:path';

import { correlator } from 'correlation-id-ts';
import { config } from 'dotenv';
import * as Rollbar from 'rollbar';

import { getEnvFile } from '@utils/get-env-file.util';
import { requestStore, RollbarOptions } from '@utils/request-store.util';

config({ path: resolve(__dirname, '../../', getEnvFile()) });

interface dataWithTraceChain extends Rollbar.Dictionary {
	body: {
		trace_chain: unknown[];
	};
}

interface objectWithException {
	exception: {
		class?: string;
		message: string;
	};
}

export const rollbar = new Rollbar({
	accessToken: String(process.env['ROLLBAR_ACCESS_TOKEN']),
	environment: String(process.env['NODE_ENV']),
	uncaughtErrorLevel: 'error',
	captureUncaught: true,
	captureUnhandledRejections: true,
	nodeSourceMaps: true,
	scrubFields: ['passwordAgain', 'password'],
	enabled: true,
	transform,
});

export function transform(data: Rollbar.Dictionary): void {
	let correlationId;
	try {
		correlationId = correlator.getId();
	} catch {
		correlationId = null;
	}

	data['custom'] ??= {};
	(data['custom'] as Record<string, unknown>)['correlationId'] = correlationId;

	const rollbarOptions = requestStore.get({ key: 'rollbar' });
	if (rollbarOptions) {
		mergeFieldsAndData({ data, rollbarOptions });
		const { issueTitle } = rollbarOptions;
		if (issueTitle) {
			overrideIssueTitle({ data, issueTitle });
		}
	}
}

export function overrideIssueTitle({
	data,
	issueTitle,
}: {
	data: Rollbar.Dictionary;
	issueTitle: string;
}): void {
	if (isDataWithTraceChain({ data })) {
		const dataWithTraceChain = data as dataWithTraceChain;
		const firstException = dataWithTraceChain.body.trace_chain[0];
		if (isObjectWithException({ data: firstException })) {
			const firstExceptionWithMessage = firstException as objectWithException;
			firstExceptionWithMessage.exception.message = issueTitle;
		}
	}
}

export function mergeFieldsAndData({
	data,
	rollbarOptions,
}: {
	data: Rollbar.Dictionary;
	rollbarOptions: RollbarOptions;
}): void {
	data['custom'] = data['custom'] ?? {};
	const custom = data['custom'] as Record<string, unknown>;
	if (rollbarOptions.fields) {
		Object.assign(custom, rollbarOptions.fields);
	}

	const fingerprint = rollbarOptions.fingerprintContext
		? { fingerprintContext: rollbarOptions.fingerprintContext }
		: undefined;
	if (rollbarOptions.data || fingerprint) {
		if (!custom['extraArgs'] || typeof custom['extraArgs'] !== 'object') {
			custom['extraArgs'] = {};
		}
		Object.assign(
			custom['extraArgs'] as Record<string, unknown>,
			rollbarOptions.data,
			fingerprint,
		);
	}
}

export function isDataWithTraceChain({ data }: { data: Rollbar.Dictionary }): boolean {
	return (
		'body' in data &&
		typeof data['body'] === 'object' &&
		data['body'] !== null &&
		'trace_chain' in data['body'] &&
		Array.isArray(data['body'].trace_chain)
	);
}

export function isObjectWithException({ data }: { data: unknown }): boolean {
	return (
		typeof data === 'object' &&
		data !== null &&
		'exception' in data &&
		typeof data.exception === 'object' &&
		data.exception !== null &&
		'message' in data.exception
	);
}

