   202→- [ ] **Step 1: Create the client**
   203→
   204→```typescript
   205→import { RollbarEnrichment } from './types';
   206→
   207→const ROLLBAR_API_URL = 'https://api.rollbar.com/api/1';
   208→
   209→interface RollbarItem {
   210→  id: number;
   211→  fingerprint: string;
   212→  first_occurrence_timestamp: number;
   213→  last_occurrence_timestamp: number;
   214→  total_occurrences: number;
   215→  title: string;
   216→}
   217→
   218→interface RollbarOccurrence {
   219→  data: {
   220→    custom?: { correlationId?: string };
   221→    body?: {
   222→      trace_chain?: Array<{ frames?: Array<{ filename: string; lineno: number; method: string }> }>;
   223→      trace?: { frames?: Array<{ filename: string; lineno: number; method: string }> };
   224→    };
   225→  };
   226→}
   227→
   228→export async function enrichWithRollbar({
   229→  readToken,
   230→  errorClass,
   231→  errorMessage,
   232→}: {
   233→  readToken: string;
   234→  errorClass: string;
   235→  errorMessage: string;
   236→}): Promise<RollbarEnrichment | null> {
   237→  const searchQuery = encodeURIComponent(`${errorClass}: ${errorMessage}`);
   238→  const itemsUrl = `${ROLLBAR_API_URL}/items/?access_token=${readToken}&status=active&query=${searchQuery}&per_page=1`;
   239→
   240→  const itemsResp = await fetch(itemsUrl);
   241→  if (!itemsResp.ok) return null;
   242→
   243→  const itemsJson = (await itemsResp.json()) as { result: { items: RollbarItem[] } };
   244→  const item = itemsJson.result.items[0];
   245→  if (!item) return null;
   246→
   247→  // Fetch most recent occurrence to get correlationId + stack trace
   248→  const occUrl = `${ROLLBAR_API_URL}/item/${item.id}/instances/?access_token=${readToken}&per_page=1`;
   249→  const occResp = await fetch(occUrl);
   250→  if (!occResp.ok) {
   251→    return {
   252→      fingerprint: item.fingerprint,
   253→      firstOccurrenceTimestamp: item.first_occurrence_timestamp,
   254→      lastOccurrenceTimestamp: item.last_occurrence_timestamp,
   255→      correlationId: null,
   256→      stackTrace: '',
   257→    };
   258→  }
   259→
   260→  const occJson = (await occResp.json()) as { result: { instances: RollbarOccurrence[] } };
   261→  const occurrence = occJson.result.instances[0];
   262→  const correlationId = occurrence?.data?.custom?.correlationId ?? null;
   263→
   264→  const frames =
   265→    occurrence?.data?.body?.trace_chain?.[0]?.frames ??
   266→    occurrence?.data?.body?.trace?.frames ??
   267→    [];
   268→
   269→  const stackTrace = frames
   270→    .slice(-10)
   271→    .map((f) => `  at ${f.method} (${f.filename}:${f.lineno})`)
   272→    .join('\n');
   273→
   274→  return {
   275→    fingerprint: item.fingerprint,
   276→    firstOccurrenceTimestamp: item.first_occurrence_timestamp,
   277→    lastOccurrenceTimestamp: item.last_occurrence_timestamp,
   278→    correlationId,
   279→    stackTrace,
   280→  };
   281→}
   282→```
