   300→- [ ] **Step 1: Create orchestrator**
   301→
   302→```typescript
   303→import { writeFileSync } from 'node:fs';
   304→import { fetchNewRelicErrors } from './newrelic-client';
   305→import { enrichWithRollbar } from './rollbar-client';
   306→import { Digest, DigestError } from './types';
   307→
   308→async function run(): Promise<void> {
   309→  const nrApiKey = process.env['NEW_RELIC_API_KEY'];
   310→  const nrAccountId = process.env['NEW_RELIC_ACCOUNT_ID'];
   311→  const rollbarToken = process.env['ROLLBAR_READ_TOKEN'];
   312→
   313→  if (!nrApiKey || !nrAccountId) {
   314→    throw new Error('NEW_RELIC_API_KEY and NEW_RELIC_ACCOUNT_ID are required');
   315→  }
   316→
   317→  console.log('Fetching New Relic errors (last 24h)...');
   318→  const nrErrors = await fetchNewRelicErrors({ apiKey: nrApiKey, accountId: nrAccountId });
   319→  console.log(`Fetched ${nrErrors.length} error groups from New Relic`);
   320→
   321→  const totalErrors24h = nrErrors.reduce((sum, e) => sum + e.count, 0);
   322→  const totalErrorsPrevious24h = nrErrors.reduce((sum, e) => sum + e.countPrevious24h, 0);
   323→  const overallChangePercent =
   324→    totalErrorsPrevious24h === 0
   325→      ? 0
   326→      : Math.round(((totalErrors24h - totalErrorsPrevious24h) / totalErrorsPrevious24h) * 100);
   327→
   328→  // Enrich top 5 errors with Rollbar (stack trace + correlationId)
   329→  const errors: DigestError[] = await Promise.all(
   330→    nrErrors.map(async (nrError, index) => {
   331→      const shouldEnrich = rollbarToken && index < 5;
   332→      const rollbar = shouldEnrich
   333→        ? await enrichWithRollbar({
   334→            readToken: rollbarToken,
   335→            errorClass: nrError.errorClass,
   336→            errorMessage: nrError.errorMessage,
   337→          })
   338→        : null;
   339→
   340→      if (rollbar) {
   341→        console.log(`  Enriched with Rollbar: ${nrError.errorClass}`);
   342→      }
   343→
   344→      return { ...nrError, rollbar };
   345→    }),
   346→  );
   347→
   348→  const digest: Digest = {
   349→    generatedAt: new Date().toISOString(),
   350→    newrelic: { totalErrors24h, totalErrorsPrevious24h, overallChangePercent },
   351→    errors,
   352→  };
   353→
   354→  writeFileSync('rollbar-digest.json', JSON.stringify(digest, null, 2));
   355→  console.log(`Digest written to rollbar-digest.json`);
   356→  console.log(`Total errors: ${totalErrors24h} (${overallChangePercent > 0 ? '+' : ''}${overallChangePercent}% vs prior 24h)`);
   357→}
   358→
   359→run().catch((err) => {
   360→  console.error('Monitor script failed:', err);
   361→  process.exit(1);
   362→});
   363→```
