import { NewRelicError } from './types';

const NR_GRAPHQL_URL = 'https://api.newrelic.com/graphql';

interface NerdGraphResponse {
	data: {
		actor: {
			account: {
				current: { results: Array<Record<string, unknown>> };
				previous: { results: Array<Record<string, unknown>> };
			};
		};
	};
}

export async function fetchNewRelicErrors({
	apiKey,
	accountId,
}: {
	apiKey: string;
	accountId: string;
}): Promise<NewRelicError[]> {
	const baseNrql =
		"SELECT count(*) as errorCount, latest(error.class) as errorClass, latest(request.uri) as requestUri FROM TransactionError WHERE appName LIKE '%Recommendations Service (production)%' FACET error.class, error.message, transactionName LIMIT 30";

	const query = `{
    actor {
      account(id: ${accountId}) {
        current: nrql(query: "${baseNrql} SINCE 24 HOURS AGO") { results }
        previous: nrql(query: "${baseNrql} SINCE 48 HOURS AGO UNTIL 24 HOURS AGO") { results }
      }
    }
  }`;

	const response = await fetch(NR_GRAPHQL_URL, {
		method: 'POST',
		headers: {
			'Content-Type': 'application/json',
			'API-Key': apiKey,
		},
		body: JSON.stringify({ query }),
	});

	if (!response.ok) {
		throw new Error(`New Relic API error: ${response.status} ${await response.text()}`);
	}

	const json = (await response.json()) as NerdGraphResponse;
	const currentResults = json.data.actor.account.current.results;
	const previousResults = json.data.actor.account.previous.results;

	const previousMap = new Map<string, number>();
	for (const row of previousResults) {
		const key = `${String(row['error.class'] ?? '')}::${String(row['error.message'] ?? '')}::${String(row['transactionName'] ?? '')}`;
		previousMap.set(key, Number(row['errorCount'] ?? 0));
	}

	return currentResults.map((row) => {
		const errorClass = String(row['error.class'] ?? 'Unknown');
		const errorMessage = String(row['error.message'] ?? '');
		const transactionName = String(row['transactionName'] ?? '');
		const requestUri = String(row['requestUri'] ?? '');
		const count = Number(row['errorCount'] ?? 0);

		const key = `${errorClass}::${errorMessage}::${transactionName}`;
		const countPrevious24h = previousMap.get(key) ?? 0;
		const changePercent =
			countPrevious24h === 0
				? 100
				: Math.round(((count - countPrevious24h) / countPrevious24h) * 100);

		return { errorClass, errorMessage, transactionName, requestUri, count, countPrevious24h, changePercent };
	});
}

