import { RollbarEnrichment } from './types';

const ROLLBAR_API_URL = 'https://api.rollbar.com/api/1';

interface RollbarItem {
	id: number;
	fingerprint: string;
	first_occurrence_timestamp: number;
	last_occurrence_timestamp: number;
	total_occurrences: number;
	title: string;
}

interface RollbarFrame {
	filename: string;
	lineno: number;
	method: string;
}

interface RollbarOccurrence {
	data: {
		custom?: { correlationId?: string };
		body?: {
			trace_chain?: Array<{ frames?: RollbarFrame[] }>;
			trace?: { frames?: RollbarFrame[] };
		};
	};
}

export async function enrichWithRollbar({
	readToken,
	errorClass,
	errorMessage,
}: {
	readToken: string;
	errorClass: string;
	errorMessage: string;
}): Promise<RollbarEnrichment | null> {
	const searchQuery = encodeURIComponent(`${errorClass}: ${errorMessage}`);
	const itemsUrl = `${ROLLBAR_API_URL}/items/?access_token=${readToken}&status=active&query=${searchQuery}&per_page=1`;

	const itemsResp = await fetch(itemsUrl);
	if (!itemsResp.ok) return null;

	const itemsJson = (await itemsResp.json()) as { result: { items: RollbarItem[] } };
	const item = itemsJson.result.items[0];
	if (!item) return null;

	const occUrl = `${ROLLBAR_API_URL}/item/${item.id}/instances/?access_token=${readToken}&per_page=1`;
	const occResp = await fetch(occUrl);
	if (!occResp.ok) {
		return {
			fingerprint: item.fingerprint,
			firstOccurrenceTimestamp: item.first_occurrence_timestamp,
			lastOccurrenceTimestamp: item.last_occurrence_timestamp,
			correlationId: null,
			stackTrace: '',
		};
	}

	const occJson = (await occResp.json()) as { result: { instances: RollbarOccurrence[] } };
	const occurrence = occJson.result.instances[0];
	const correlationId = occurrence?.data?.custom?.correlationId ?? null;

	const frames =
		occurrence?.data?.body?.trace_chain?.[0]?.frames ??
		occurrence?.data?.body?.trace?.frames ??
		[];

	const stackTrace = frames
		.slice(-10)
		.map((f) => `  at ${f.method} (${f.filename}:${f.lineno})`)
		.join('\n');

	return {
		fingerprint: item.fingerprint,
		firstOccurrenceTimestamp: item.first_occurrence_timestamp,
		lastOccurrenceTimestamp: item.last_occurrence_timestamp,
		correlationId,
		stackTrace,
	};
}

