     4→import { config } from 'dotenv';
     5→import * as Rollbar from 'rollbar';
     6→
     7→import { getEnvFile } from '@utils/get-env-file.util';
     8→import { requestStore, RollbarOptions } from '@utils/request-store.util';
     9→
    10→config({ path: resolve(__dirname, '../../', getEnvFile()) });
    11→
    12→interface dataWithTraceChain extends Rollbar.Dictionary {
    13→	body: {
    14→		trace_chain: unknown[];
    15→	};
    16→}
    17→
    18→interface objectWithException {
    19→	exception: {
    20→		class?: string;
    21→		message: string;
    22→	};
    23→}
    24→
    25→export const rollbar = new Rollbar({
    26→	accessToken: String(process.env['ROLLBAR_ACCESS_TOKEN']),
    27→	environment: String(process.env['NODE_ENV']),
    28→	uncaughtErrorLevel: 'error',
    29→	captureUncaught: true,
    30→	captureUnhandledRejections: true,
    31→	nodeSourceMaps: true,
    32→	scrubFields: ['passwordAgain', 'password'],
    33→	enabled: true,
    34→	transform,
    35→});
    36→
    37→export function transform(data: Rollbar.Dictionary): void {
    38→	let correlationId;
    39→	try {
    40→		correlationId = correlator.getId();
    41→	} catch {
    42→		correlationId = null;
    43→	}
    44→
    45→	data['custom'] ??= {};
    46→	(data['custom'] as Record<string, unknown>)['correlationId'] = correlationId;
    47→
    48→	const rollbarOptions = requestStore.get({ key: 'rollbar' });
    49→	if (rollbarOptions) {
    50→		mergeFieldsAndData({ data, rollbarOptions });
    51→		const { issueTitle } = rollbarOptions;
    52→		if (issueTitle) {
    53→			overrideIssueTitle({ data, issueTitle });
    54→		}
    55→	}
    56→}
    57→
    58→export function overrideIssueTitle({
    59→	data,
    60→	issueTitle,
    61→}: {
    62→	data: Rollbar.Dictionary;
    63→	issueTitle: string;
    64→}): void {
    65→	if (isDataWithTraceChain({ data })) {
    66→		const dataWithTraceChain = data as dataWithTraceChain;
    67→		const firstException = dataWithTraceChain.body.trace_chain[0];
    68→		if (isObjectWithException({ data: firstException })) {
    69→			const firstExceptionWithMessage = firstException as objectWithException;
    70→			firstExceptionWithMessage.exception.message = issueTitle;
    71→		}
    72→	}
    73→}
    74→
    75→export function mergeFieldsAndData({
    76→	data,
    77→	rollbarOptions,
    78→}: {
    79→	data: Rollbar.Dictionary;
    80→	rollbarOptions: RollbarOptions;
    81→}): void {
    82→	data['custom'] = data['custom'] ?? {};
    83→	const custom = data['custom'] as Record<string, unknown>;
    84→	if (rollbarOptions.fields) {
    85→		Object.assign(custom, rollbarOptions.fields);
    86→	}
    87→
    88→	const fingerprint = rollbarOptions.fingerprintContext
    89→		? { fingerprintContext: rollbarOptions.fingerprintContext }
    90→		: undefined;
    91→	if (rollbarOptions.data || fingerprint) {
    92→		if (!custom['extraArgs'] || typeof custom['extraArgs'] !== 'object') {
    93→			custom['extraArgs'] = {};
    94→		}
    95→		Object.assign(
    96→			custom['extraArgs'] as Record<string, unknown>,
    97→			rollbarOptions.data,
    98→			fingerprint,
    99→		);
   100→	}
   101→}
   102→
   103→export function isDataWithTraceChain({ data }: { data: Rollbar.Dictionary }): boolean {
   104→	return (
   105→		'body' in data &&
   106→		typeof data['body'] === 'object' &&
   107→		data['body'] !== null &&
   108→		'trace_chain' in data['body'] &&
   109→		Array.isArray(data['body'].trace_chain)
   110→	);
   111→}
   112→
   113→export function isObjectWithException({ data }: { data: unknown }): boolean {
   114→	return (
   115→		typeof data === 'object' &&
   116→		data !== null &&
   117→		'exception' in data &&
   118→		typeof data.exception === 'object' &&
   119→		data.exception !== null &&
   120→		'message' in data.exception
   121→	);
   122→}
