   100→
   101→Fetches top 30 error groups from the last 24h via NerdGraph, compares with prior 24h, returns typed results.
   102→
   103→- [ ] **Step 1: Create the client**
   104→
   105→```typescript
   106→import { NewRelicError } from './types';
   107→
   108→const NR_GRAPHQL_URL = 'https://api.newrelic.com/graphql';
   109→
   110→interface NerdGraphResponse {
   111→  data: {
   112→    actor: {
   113→      account: {
   114→        current: { results: Array<Record<string, unknown>> };
   115→        previous: { results: Array<Record<string, unknown>> };
   116→      };
   117→    };
   118→  };
   119→}
   120→
   121→export async function fetchNewRelicErrors({
   122→  apiKey,
   123→  accountId,
   124→}: {
   125→  apiKey: string;
   126→  accountId: string;
   127→}): Promise<NewRelicError[]> {
   128→  const nrql = `
   129→    SELECT count(*) as errorCount, latest(error.class) as errorClass, latest(request.uri) as requestUri
   130→    FROM TransactionError
   131→    FACET error.class, error.message, transactionName
   132→    LIMIT 30
   133→  `;
   134→
   135→  const query = `{
   136→    actor {
   137→      account(id: ${accountId}) {
   138→        current: nrql(query: "${nrql} SINCE 24 HOURS AGO") { results }
   139→        previous: nrql(query: "${nrql} SINCE 48 HOURS AGO UNTIL 24 HOURS AGO") { results }
   140→      }
   141→    }
   142→  }`;
   143→
   144→  const response = await fetch(NR_GRAPHQL_URL, {
   145→    method: 'POST',
   146→    headers: {
   147→      'Content-Type': 'application/json',
   148→      'API-Key': apiKey,
   149→    },
   150→    body: JSON.stringify({ query }),
   151→  });
   152→
   153→  if (!response.ok) {
   154→    throw new Error(`New Relic API error: ${response.status} ${await response.text()}`);
   155→  }
   156→
   157→  const json = (await response.json()) as NerdGraphResponse;
   158→  const currentResults = json.data.actor.account.current.results;
   159→  const previousResults = json.data.actor.account.previous.results;
   160→
   161→  const previousMap = new Map<string, number>();
   162→  for (const row of previousResults) {
   163→    const key = `${String(row['error.class'] ?? '')}::${String(row['error.message'] ?? '')}::${String(row['transactionName'] ?? '')}`;
   164→    previousMap.set(key, Number(row['errorCount'] ?? 0));
   165→  }
   166→
   167→  return currentResults.map((row) => {
   168→    const errorClass = String(row['error.class'] ?? 'Unknown');
   169→    const errorMessage = String(row['error.message'] ?? '');
   170→    const transactionName = String(row['transactionName'] ?? '');
   171→    const requestUri = String(row['requestUri'] ?? '');
   172→    const count = Number(row['errorCount'] ?? 0);
   173→
   174→    const key = `${errorClass}::${errorMessage}::${transactionName}`;
   175→    const countPrevious24h = previousMap.get(key) ?? 0;
   176→    const changePercent =
   177→      countPrevious24h === 0
   178→        ? 100
   179→        : Math.round(((count - countPrevious24h) / countPrevious24h) * 100);
   180→
   181→    return { errorClass, errorMessage, transactionName, requestUri, count, countPrevious24h, changePercent };
   182→  });
   183→}
   184→```
