   354→  writeFileSync('rollbar-digest.json', JSON.stringify(digest, null, 2));
   355→  console.log(`Digest written to rollbar-digest.json`);
   356→  console.log(`Total errors: ${totalErrors24h} (${overallChangePercent > 0 ? '+' : ''}${overallChangePercent}% vs prior 24h)`);
   357→}
   358→
   359→run().catch((err) => {
   360→  console.error('Monitor script failed:', err);
   361→  process.exit(1);
   362→});
