import { writeFileSync } from 'node:fs';

import { fetchNewRelicErrors } from './newrelic-client';
import { enrichWithRollbar } from './rollbar-client';
import { Digest, DigestError } from './types';

async function run(): Promise<void> {
	const nrApiKey = process.env['NEW_RELIC_API_KEY'];
	const nrAccountId = process.env['NEW_RELIC_ACCOUNT_ID'];
	const rollbarToken = process.env['ROLLBAR_READ_TOKEN'];

	if (!nrApiKey || !nrAccountId) {
		throw new Error('NEW_RELIC_API_KEY and NEW_RELIC_ACCOUNT_ID are required');
	}

	console.log('Fetching New Relic errors (last 24h)...');
	const nrErrors = await fetchNewRelicErrors({ apiKey: nrApiKey, accountId: nrAccountId });
	console.log(`Fetched ${nrErrors.length} error groups from New Relic`);

	const totalErrors24h = nrErrors.reduce((sum, e) => sum + e.count, 0);
	const totalErrorsPrevious24h = nrErrors.reduce((sum, e) => sum + e.countPrevious24h, 0);
	const overallChangePercent =
		totalErrorsPrevious24h === 0
			? 0
			: Math.round(((totalErrors24h - totalErrorsPrevious24h) / totalErrorsPrevious24h) * 100);

	const errors: DigestError[] = await Promise.all(
		nrErrors.map(async (nrError, index) => {
			const shouldEnrich = rollbarToken !== undefined && index < 5;
			const rollbar = shouldEnrich
				? await enrichWithRollbar({
						readToken: rollbarToken,
						errorClass: nrError.errorClass,
						errorMessage: nrError.errorMessage,
					})
				: null;

			if (rollbar) {
				console.log(`  Enriched with Rollbar: ${nrError.errorClass}`);
			}

			return { ...nrError, rollbar };
		}),
	);

	const digest: Digest = {
		generatedAt: new Date().toISOString(),
		newrelic: { totalErrors24h, totalErrorsPrevious24h, overallChangePercent },
		errors,
	};

	writeFileSync('rollbar-digest.json', JSON.stringify(digest, null, 2));
	console.log('Digest written to rollbar-digest.json');
	console.log(
		`Total errors: ${totalErrors24h} (${overallChangePercent > 0 ? '+' : ''}${overallChangePercent}% vs prior 24h)`,
	);
}

run().catch((err: unknown) => {
	console.error('Monitor script failed:', err);
	process.exit(1);
});

